// COMPASS LOGO
// ═══════════════════════════════════════════════════════════════════════════════
function Compass({ size = 64, spin = false }) {
  return (
    <svg viewBox="0 0 120 120" width={size} height={size}
      style={spin ? { animation: "spin 12s linear infinite" } : {}}>
      <defs>
        <linearGradient id="cg1" x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stopColor="#7c3aed"/><stop offset="100%" stopColor="#a855f7"/>
        </linearGradient>
      </defs>
      <circle cx="60" cy="60" r="56" fill="none" stroke="url(#cg1)" strokeWidth="1.5" opacity="0.5"/>
      {[0,45,90,135,180,225,270,315].map((deg,i)=>{
        const r1=i%2===0?42:46, r2=52, rad=deg*Math.PI/180;
        return <line key={deg}
          x1={60+r1*Math.sin(rad)} y1={60-r1*Math.cos(rad)}
          x2={60+r2*Math.sin(rad)} y2={60-r2*Math.cos(rad)}
          stroke="url(#cg1)" strokeWidth={i%2===0?"2":"1"} opacity="0.6"/>;
      })}
      <polygon points="60,9 54,60 60,51 66,60" fill="url(#cg1)"/>
      <polygon points="60,111 66,60 60,69 54,60" fill="#2d1f5e"/>
      <polygon points="111,60 60,54 69,60 60,66" fill="#a855f7" opacity="0.7"/>
      <polygon points="9,60 60,66 51,60 60,54" fill="#2d1f5e" opacity="0.9"/>
      <circle cx="60" cy="60" r="6" fill="url(#cg1)"/>
      <circle cx="60" cy="60" r="2.5" fill="#fff"/>
    </svg>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// PROGRESS RING
// ═══════════════════════════════════════════════════════════════════════════════
function Ring({ pct, size = 120, label, sublabel }) {
  const r = (size - 16) / 2;
  const circ = 2 * Math.PI * r;
  const offset = circ - (pct / 100) * circ;
  const color = pct >= PASS_THRESHOLD ? T.green : pct >= 60 ? T.amber : pct > 0 ? T.red : T.muted;
  return (
    <div style={{ position:"relative", width:size, height:size, margin:"0 auto" }}>
      <svg width={size} height={size} style={{ transform:"rotate(-90deg)" }}>
        <circle cx={size/2} cy={size/2} r={r} fill="none" stroke="var(--border)" strokeWidth="8"/>
        <circle cx={size/2} cy={size/2} r={r} fill="none" stroke={color} strokeWidth="8"
          strokeDasharray={circ} strokeDashoffset={offset} strokeLinecap="round"
          style={{ transition:"stroke-dashoffset 0.8s ease" }}/>
      </svg>
      <div style={{ position:"absolute", inset:0, display:"flex", flexDirection:"column",
        alignItems:"center", justifyContent:"center" }}>
        <div style={{ fontSize:size*0.26, fontWeight:900, color, lineHeight:1 }}>{label ?? pct + "%"}</div>
        {sublabel && <div style={{ fontSize:11, color:T.muted, marginTop:2 }}>{sublabel}</div>}
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// QUIZ ENGINE — shared by full exams and topic practice
// ═══════════════════════════════════════════════════════════════════════════════
// ═══════════════════════════════════════════════════════════════════════════════
// QUIZ ENGINE — handles practice, adaptive, and timed mock exams
//   timed:        if true, shows a countdown that can be paused
//   initialState: resume a saved in-progress mock (idx, answers, secondsLeft, paused)
//   onProgress:   called on every state change so a mock can be cloud-saved mid-exam
// ═══════════════════════════════════════════════════════════════════════════════
function Quiz({ title, questions, instantFeedback, timed, initialState, onProgress, onFinish, onExit }) {
  const [idx, setIdx] = useState(initialState?.idx || 0);
  const [answers, setAnswers] = useState(initialState?.answers || {});
  const [revealed, setRevealed] = useState({});
  const [secondsLeft, setSecondsLeft] = useState(
    initialState?.secondsLeft != null ? initialState.secondsLeft : MOCK_SECONDS
  );
  const [paused, setPaused] = useState(false);
  const [pausedTotal, setPausedTotal] = useState(initialState?.pausedTotal || 0);

  const q = questions[idx];
  const chosen = answers[q.id];
  const isRevealed = instantFeedback && revealed[q.id];
  const total = questions.length;
  const letters = ["A", "B", "C", "D"];

  // Countdown timer (mock only)
  useEffect(() => {
    if (!timed || paused) return;
    if (secondsLeft <= 0) { finish(); return; }
    const t = setInterval(() => setSecondsLeft(s => s - 1), 1000);
    return () => clearInterval(t);
  }, [timed, paused, secondsLeft]);

  // Count paused seconds (for honesty display)
  useEffect(() => {
    if (!timed || !paused) return;
    const t = setInterval(() => setPausedTotal(p => p + 1), 1000);
    return () => clearInterval(t);
  }, [timed, paused]);

  // Persist progress for mock resume (debounced via effect)
  useEffect(() => {
    if (timed && onProgress) {
      onProgress({ idx, answers, secondsLeft, pausedTotal });
    }
  }, [idx, answers, secondsLeft, pausedTotal]);

  const pick = (optIdx) => {
    if (isRevealed) return;
    setAnswers(a => ({ ...a, [q.id]: optIdx }));
    if (instantFeedback) setRevealed(r => ({ ...r, [q.id]: true }));
  };
  const next = () => { if (idx < total - 1) setIdx(idx + 1); else finish(); };
  const prev = () => { if (idx > 0) setIdx(idx - 1); };

  const finish = () => {
    let correct = 0;
    const breakdown = {};
    const missed = [];
    questions.forEach(qq => {
      const ok = answers[qq.id] === qq.answer;
      if (ok) correct++; else missed.push(qq.id);
      if (!breakdown[qq.domain]) breakdown[qq.domain] = { correct: 0, total: 0 };
      breakdown[qq.domain].total++;
      if (ok) breakdown[qq.domain].correct++;
    });
    const pct = Math.round((correct / total) * 100);
    const elapsed = timed ? (MOCK_SECONDS - secondsLeft) : null;
    onFinish({ pct, correct, total, breakdown, answers, missed, elapsed, pausedTotal });
  };

  const fmt = (s) => {
    const m = Math.floor(Math.max(0, s) / 60);
    const sec = Math.max(0, s) % 60;
    return `${m}:${String(sec).padStart(2, "0")}`;
  };
  const timeLow = timed && secondsLeft <= 120;

  // Pause overlay
  if (paused) {
    return (
      <div className="safe-top safe-bottom" style={{ minHeight: "100vh", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: 24 }}>
        <Compass size={64} />
        <div style={{ fontSize: 22, fontWeight: 900, marginTop: 20, color: T.text }}>Paused</div>
        <div style={{ fontSize: 14, color: T.muted, marginTop: 6, textAlign: "center", lineHeight: 1.5 }}>
          Time left: {fmt(secondsLeft)}<br />
          Your progress is saved — you can safely leave and resume later.
        </div>
        <button onClick={() => setPaused(false)}
          style={{ marginTop: 28, padding: "15px 40px", borderRadius: 14, fontWeight: 800, fontSize: 16,
            background: `linear-gradient(135deg,${T.violet},${T.violet2})`, color: "#fff" }}>
          Resume
        </button>
        <button onClick={onExit}
          style={{ marginTop: 12, padding: "12px 24px", fontSize: 14, color: T.muted, fontWeight: 600 }}>
          Save &amp; Exit
        </button>
      </div>
    );
  }

  return (
    <div style={{ minHeight: "100vh", display: "flex", flexDirection: "column" }} className="safe-top safe-bottom">
      {/* Header */}
      <div style={{ padding: "14px 18px", display: "flex", alignItems: "center", justifyContent: "space-between",
        borderBottom: `1px solid ${T.border}`, position: "sticky", top: 0, background: T.bg, zIndex: 10 }}>
        <button onClick={onExit} style={{ fontSize: 14, color: T.muted, fontWeight: 600 }}>✕ Exit</button>
        <div style={{ fontSize: 13, fontWeight: 700, color: T.sub, textAlign: "center", flex: 1 }}>{title}</div>
        {timed ? (
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <span style={{ fontSize: 14, fontWeight: 800, color: timeLow ? T.red : T.sub,
              fontVariantNumeric: "tabular-nums" }}>{fmt(secondsLeft)}</span>
            <button onClick={() => setPaused(true)} style={{ fontSize: 12, color: T.violet2, fontWeight: 700 }}>⏸</button>
          </div>
        ) : (
          <div style={{ fontSize: 13, color: T.muted, fontWeight: 600 }}>{idx + 1}/{total}</div>
        )}
      </div>

      {/* Progress bar */}
      <div style={{ height: 3, background: T.border }}>
        <div style={{ height: "100%", width: `${((idx + 1) / total) * 100}%`,
          background: `linear-gradient(90deg,${T.violet},${T.violet2})`, transition: "width 0.3s ease" }} />
      </div>

      {/* Question */}
      <div key={q.id} className="slideIn" style={{ flex: 1, padding: "24px 18px", overflowY: "auto" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
          <span style={{ display: "inline-block", fontSize: 11, fontWeight: 700, color: T.violet2,
            background: T.violetSoft, padding: "4px 12px", borderRadius: 20 }}>{q.domain}</span>
          {timed && <span style={{ fontSize: 11, color: T.muted, fontWeight: 600 }}>{idx + 1}/{total}</span>}
        </div>
        <div style={{ fontSize: 18, fontWeight: 600, lineHeight: 1.5, marginBottom: 24, color: T.text }}>{q.q}</div>

        <div style={{ display: "flex", flexDirection: "column", gap: 11 }}>
          {q.options.map((opt, i) => {
            const isChosen = chosen === i;
            const isCorrect = i === q.answer;
            let bg = T.card, border = T.border, color = T.text, badge = T.violetSoft, badgeColor = T.violet2;
            if (isRevealed) {
              if (isCorrect) { bg = T.greenSoft; border = T.green; badge = T.green; badgeColor = "#fff"; }
              else if (isChosen) { bg = T.redSoft; border = T.red; badge = T.red; badgeColor = "#fff"; }
            } else if (isChosen) { bg = T.violetSoft; border = T.violet; badge = T.violet; badgeColor = "#fff"; }
            return (
              <button key={i} onClick={() => pick(i)}
                style={{ display: "flex", alignItems: "center", gap: 14, textAlign: "left", padding: "16px 16px",
                  borderRadius: 14, background: bg, border: `1.5px solid ${border}`, transition: "all 0.15s",
                  width: "100%", minHeight: 58 }}>
                <span style={{ flexShrink: 0, width: 28, height: 28, borderRadius: 8, background: badge, color: badgeColor,
                  fontWeight: 800, fontSize: 14, display: "flex", alignItems: "center", justifyContent: "center" }}>
                  {isRevealed && isCorrect ? "✓" : isRevealed && isChosen ? "✕" : letters[i]}
                </span>
                <span style={{ fontSize: 15, lineHeight: 1.4, color }}>{opt}</span>
              </button>
            );
          })}
        </div>

        {isRevealed && (
          <div className="fadeUp" style={{ marginTop: 20, padding: "16px 18px", borderRadius: 14,
            background: chosen === q.answer ? T.greenSoft : T.amberSoft,
            border: `1px solid ${chosen === q.answer ? T.green : T.amber}44` }}>
            <div style={{ fontSize: 12, fontWeight: 800, letterSpacing: 0.5,
              color: chosen === q.answer ? T.green : T.amber, marginBottom: 8 }}>
              {chosen === q.answer ? "✓ CORRECT" : "✕ NOT QUITE"}
            </div>
            <div style={{ fontSize: 14, lineHeight: 1.6, color: T.sub }}>{q.explain}</div>
          </div>
        )}
      </div>

      {/* Footer nav */}
      <div style={{ padding: "14px 18px", borderTop: `1px solid ${T.border}`, display: "flex", gap: 12,
        background: T.bg, position: "sticky", bottom: 0 }}>
        {idx > 0 && (
          <button onClick={prev} style={{ padding: "15px 22px", borderRadius: 14, border: `1.5px solid ${T.border}`,
            color: T.sub, fontWeight: 700, fontSize: 15 }}>←</button>
        )}
        <button onClick={next} disabled={chosen === undefined}
          style={{ flex: 1, padding: "15px", borderRadius: 14, fontWeight: 800, fontSize: 16,
            background: chosen === undefined ? T.card : `linear-gradient(135deg,${T.violet},${T.violet2})`,
            color: chosen === undefined ? T.muted : "#fff", opacity: chosen === undefined ? 0.6 : 1, transition: "all 0.15s" }}>
          {idx === total - 1 ? "Finish & See Score" : "Next →"}
        </button>
      </div>
    </div>
  );
}
function Results({ result, title, questions, onRetry, onReview, onHome, isBest, showTime }) {
  const { pct, correct, total, breakdown, elapsed, pausedTotal } = result;
  const passed = pct >= PASS_THRESHOLD;
  const fmt = (s) => { const m = Math.floor((s||0)/60); const sec = (s||0)%60; return `${m}:${String(sec).padStart(2,"0")}`; };
  return (
    <div className="safe-top safe-bottom" style={{ minHeight:"100vh", padding:"32px 20px 24px", overflowY:"auto" }}>
      <div className="fadeUp" style={{ textAlign:"center", marginBottom:8 }}>
        <div style={{ fontSize:13, color:T.muted, fontWeight:700, letterSpacing:1, textTransform:"uppercase" }}>{title}</div>
      </div>

      <div className="fadeUp" style={{ marginTop:24, marginBottom:8, animation:"pop 0.5s ease" }}>
        <Ring pct={pct} size={160} sublabel={`${correct} of ${total}`}/>
      </div>

      <div className="fadeUp" style={{ textAlign:"center", marginTop:8, marginBottom:28 }}>
        <div style={{ fontSize:22, fontWeight:900, color: passed ? T.green : T.amber }}>
          {passed ? "Passing Score! 🎉" : pct >= 60 ? "Almost There" : "Keep Studying"}
        </div>
        <div style={{ fontSize:14, color:T.muted, marginTop:4 }}>
          Target to pass: {PASS_THRESHOLD}%
        </div>
        {isBest && (
          <div style={{ display:"inline-block", marginTop:12, fontSize:12, fontWeight:800,
            color:T.violet2, background:T.violetSoft, padding:"6px 16px", borderRadius:20 }}>
            ⭐ New Best Score
          </div>
        )}
        {showTime && (
          <div style={{ marginTop:14, fontSize:12.5, color:T.muted }}>
            Time used: <strong style={{color:T.sub}}>{fmt(elapsed)}</strong>
            {pausedTotal > 0 && <> · Paused: <strong style={{color:T.amber}}>{fmt(pausedTotal)}</strong></>}
          </div>
        )}
      </div>

      {/* Domain breakdown */}
      <div className="fadeUp" style={{ background:T.card, borderRadius:18, padding:"20px 18px", marginBottom:16 }}>
        <div style={{ fontSize:14, fontWeight:800, marginBottom:16 }}>Performance by Topic</div>
        <div style={{ display:"flex", flexDirection:"column", gap:13 }}>
          {Object.entries(breakdown).sort((a,b)=>(a[1].correct/a[1].total)-(b[1].correct/b[1].total)).map(([dom, d]) => {
            const dp = Math.round((d.correct / d.total) * 100);
            const c = dp >= 80 ? T.green : dp >= 50 ? T.amber : T.red;
            return (
              <div key={dom}>
                <div style={{ display:"flex", justifyContent:"space-between", marginBottom:5 }}>
                  <span style={{ fontSize:13, color:T.sub, fontWeight:600 }}>{dom}</span>
                  <span style={{ fontSize:13, color:c, fontWeight:800 }}>{d.correct}/{d.total}</span>
                </div>
                <div style={{ height:6, background:T.border, borderRadius:3, overflow:"hidden" }}>
                  <div style={{ height:"100%", width:`${dp}%`, background:c, borderRadius:3,
                    transition:"width 0.6s ease" }}/>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Actions */}
      <div style={{ display:"flex", flexDirection:"column", gap:11 }}>
        <button onClick={onReview} style={{ padding:"15px", borderRadius:14, fontWeight:800, fontSize:15,
          background:`linear-gradient(135deg,${T.violet},${T.violet2})`, color:"#fff" }}>
          📖 Review All Answers
        </button>
        <div style={{ display:"flex", gap:11 }}>
          <button onClick={onRetry} style={{ flex:1, padding:"15px", borderRadius:14, fontWeight:700,
            fontSize:15, border:`1.5px solid ${T.border}`, color:T.sub }}>
            ↻ Retake
          </button>
          <button onClick={onHome} style={{ flex:1, padding:"15px", borderRadius:14, fontWeight:700,
            fontSize:15, border:`1.5px solid ${T.border}`, color:T.sub }}>
            Home
          </button>
        </div>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// REVIEW SCREEN — see every question with correct answer + explanation
// ═══════════════════════════════════════════════════════════════════════════════
function Review({ questions, answers, onBack }) {
  const letters = ["A","B","C","D"];
  return (
    <div className="safe-top safe-bottom" style={{ minHeight:"100vh" }}>
      <div style={{ padding:"14px 18px", display:"flex", alignItems:"center", justifyContent:"space-between",
        borderBottom:`1px solid ${T.border}`, position:"sticky", top:0, background:T.bg, zIndex:10 }}>
        <button onClick={onBack} style={{ fontSize:14, color:T.muted, fontWeight:600 }}>← Back</button>
        <div style={{ fontSize:14, fontWeight:700 }}>Answer Review</div>
        <div style={{ width:40 }}/>
      </div>
      <div style={{ padding:"18px" }}>
        {questions.map((q, n) => {
          const chosen = answers[q.id];
          const correct = chosen === q.answer;
          return (
            <div key={q.id} style={{ background:T.card, borderRadius:16, padding:"18px", marginBottom:14 }}>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:10 }}>
                <span style={{ fontSize:11, fontWeight:700, color:T.violet2, background:T.violetSoft,
                  padding:"3px 10px", borderRadius:12 }}>{q.domain}</span>
                <span style={{ fontSize:18 }}>{correct ? "✅" : "❌"}</span>
              </div>
              <div style={{ fontSize:15, fontWeight:600, lineHeight:1.5, marginBottom:14 }}>
                <span style={{ color:T.muted, marginRight:6 }}>{n+1}.</span>{q.q}
              </div>
              <div style={{ display:"flex", flexDirection:"column", gap:7, marginBottom:14 }}>
                {q.options.map((opt, i) => {
                  const isAns = i === q.answer;
                  const isChosen = i === chosen;
                  let bg = "transparent", border = T.border, color = T.sub;
                  if (isAns) { bg = T.greenSoft; border = T.green; color = T.text; }
                  else if (isChosen) { bg = T.redSoft; border = T.red; color = T.text; }
                  return (
                    <div key={i} style={{ display:"flex", gap:10, alignItems:"center",
                      padding:"11px 13px", borderRadius:10, background:bg, border:`1px solid ${border}` }}>
                      <span style={{ flexShrink:0, fontSize:12, fontWeight:800,
                        color: isAns ? T.green : isChosen ? T.red : T.muted }}>{letters[i]}</span>
                      <span style={{ fontSize:14, lineHeight:1.4, color }}>{opt}</span>
                    </div>
                  );
                })}
              </div>
              <div style={{ padding:"13px 15px", borderRadius:12, background:T.card2,
                borderLeft:`3px solid ${T.violet}` }}>
                <div style={{ fontSize:11, fontWeight:800, color:T.violet2, marginBottom:6, letterSpacing:0.5 }}>WHY</div>
                <div style={{ fontSize:13.5, lineHeight:1.6, color:T.sub }}>{q.explain}</div>
              </div>
            </div>
          );
        })}
        <button onClick={onBack} style={{ width:"100%", padding:"15px", borderRadius:14, fontWeight:800,
          fontSize:15, background:`linear-gradient(135deg,${T.violet},${T.violet2})`, color:"#fff", marginTop:6 }}>
          Done
        </button>
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════════
// MAIN APP
// ═══════════════════════════════════════════════════════════════════════════════
// ═══════════════════════════════════════════════════════════════════════════════
// MAIN APP
// ═══════════════════════════════════════════════════════════════════════════════
function App() {
  const [store, setStore] = useState({});
  const [loaded, setLoaded] = useState(false);
  const [syncing, setSyncing] = useState(false);
  const [cloudOk, setCloudOk] = useState(true);
  const [view, setView] = useState("home");
  const [mode, setMode] = useState(null);
  const [activeQuestions, setActiveQuestions] = useState([]);
  const [activeTitle, setActiveTitle] = useState("");
  const [activeTimed, setActiveTimed] = useState(false);
  const [resumeState, setResumeState] = useState(null);
  const [instant, setInstant] = useState(false);
  const [lastResult, setLastResult] = useState(null);
  const [wasBest, setWasBest] = useState(false);

  useEffect(() => { cloudLoad().then(d => { setStore(d || {}); setCloudOk(cloudWasReachable); setLoaded(true); }); }, []);

  // Re-pull cloud progress whenever the app returns to the foreground, so a
  // suspended iPhone PWA and a laptop tab never overwrite each other with
  // stale data — merge keeps the best of both.
  useEffect(() => {
    const refresh = () => {
      if (document.visibilityState !== "visible") return;
      cloudFetch().then(cloud => {
        setCloudOk(cloud !== null);
        if (cloud) setStore(s => {
          const m = mergeStores(s, cloud);
          localSave(m);
          if (!sameData(m, mergeStores(cloud, cloud))) cloudPush(m); // upload any progress the cloud is missing
          return m;
        });
      });
    };
    document.addEventListener("visibilitychange", refresh);
    window.addEventListener("focus", refresh);
    return () => {
      document.removeEventListener("visibilitychange", refresh);
      window.removeEventListener("focus", refresh);
    };
  }, []);

  const persist = (next) => {
    setStore(next); setSyncing(true);
    cloudSave(next).then(ok => { setSyncing(false); setCloudOk(ok); });
  };

  // ── Stored data ──
  const bestExam = store.bestExam || {};       // {1: pct, ...} practice
  const bestTopic = store.bestTopic || {};
  const bestMock = store.bestMock || {};        // {1: pct, 2: pct}
  const missedCounts = store.missedCounts || {}; // {qid: timesMissed}
  const mockProgress = store.mockProgress || {}; // {1: {idx, answers, secondsLeft, pausedTotal, questionIds}}

  // ── Readiness scores (two separate tracks) ──
  const practiceBests = Array.from({ length: NUM_PRACTICE }, (_, i) => bestExam[i + 1] || 0);
  const practiceReadiness = Math.round(practiceBests.reduce((a, b) => a + b, 0) / NUM_PRACTICE);
  const practiceExamsTaken = practiceBests.filter(s => s > 0).length;
  const allPracticeDone = practiceExamsTaken === NUM_PRACTICE;

  const mockBests = Array.from({ length: NUM_MOCKS }, (_, i) => bestMock[i + 1] || 0);
  const mocksTaken = mockBests.filter(s => s > 0).length;
  const mockReadiness = mocksTaken > 0
    ? Math.round(mockBests.reduce((a, b) => a + b, 0) / mocksTaken)
    : 0;

  // ── Starters ──
  const startPractice = (examNum) => {
    // Fixed dedicated set per exam (no cross-exam overlap); shuffle only answer positions each attempt
    const ids = EXAM_SETS[examNum - 1] || [];
    const qs = ids.map(id => PRACTICE_POOL.find(q => q.id === id)).filter(Boolean);
    setMode({ type: "practice", id: examNum });
    setActiveQuestions(shuffle(qs).map(shuffleOptions)); // question order + answer order shuffled, but same fixed set
    setActiveTitle(`Practice Exam ${examNum}`);
    setActiveTimed(false); setResumeState(null);
    setView("quiz");
  };

  const startTopic = (domain) => {
    const pool = PRACTICE_POOL.filter(q => q.domain === domain);
    setMode({ type: "topic", domain });
    setActiveQuestions(buildSet(pool, Math.min(15, pool.length)));
    setActiveTitle(domain);
    setActiveTimed(false); setResumeState(null);
    setView("quiz");
  };

  const startAdaptive = () => {
    // Weight by how often each question was missed; mix in a few fresh
    const missedIds = Object.keys(missedCounts).filter(id => missedCounts[id] > 0);
    const missedQs = PRACTICE_POOL.filter(q => missedIds.includes(q.id));
    const weighted = [];
    missedQs.forEach(q => { for (let k = 0; k < (missedCounts[q.id] || 1); k++) weighted.push(q); });
    let pick = shuffle(weighted).filter((q, i, arr) => arr.findIndex(x => x.id === q.id) === i);
    if (pick.length < ADAPTIVE_SIZE) {
      const fresh = shuffle(PRACTICE_POOL.filter(q => !missedIds.includes(q.id)));
      pick = [...pick, ...fresh].slice(0, ADAPTIVE_SIZE);
    } else {
      pick = pick.slice(0, ADAPTIVE_SIZE);
    }
    setMode({ type: "adaptive" });
    setActiveQuestions(pick.map(shuffleOptions));
    setActiveTitle("Adaptive Review");
    setActiveTimed(false); setResumeState(null);
    setView("quiz");
  };

  const startMock = (mockNum) => {
    const saved = mockProgress[mockNum];
    if (saved && saved.questionIds) {
      // Resume: rebuild exact question set from saved IDs (preserve order + saved option order if present)
      const qs = saved.questionIds.map(id => {
        const found = MOCK_POOL.find(q => q.id === id);
        return found;
      }).filter(Boolean);
      setActiveQuestions(saved.questionSnapshot || qs);
      setResumeState({ idx: saved.idx, answers: saved.answers, secondsLeft: saved.secondsLeft, pausedTotal: saved.pausedTotal });
    } else {
      const qs = buildSet(MOCK_POOL, MOCK_SIZE);
      setActiveQuestions(qs);
      setResumeState(null);
    }
    setMode({ type: "mock", id: mockNum });
    setActiveTitle(`Mock Exam ${mockNum}`);
    setActiveTimed(true);
    setView("quiz");
  };

  // Save mock progress mid-exam (for resume after exit)
  const onMockProgress = (prog) => {
    if (!mode || mode.type !== "mock") return;
    const next = {
      ...store,
      mockProgress: {
        ...mockProgress,
        [mode.id]: {
          ...prog,
          questionIds: activeQuestions.map(q => q.id),
          questionSnapshot: activeQuestions, // preserve shuffled options exactly
        },
      },
    };
    setStore(next);
    cloudSaveThrottled(next); // silent save — local every tick, cloud at most every few seconds
  };

  const onFinish = (result) => {
    setLastResult(result);
    let best = false;
    let next = { ...store };

    // Track missed questions for adaptive mode (practice + adaptive only)
    if (mode.type === "practice" || mode.type === "adaptive" || mode.type === "topic") {
      const mc = { ...missedCounts };
      (result.missed || []).forEach(id => { mc[id] = (mc[id] || 0) + 1; });
      // reduce count for correctly-answered repeats so mastery decays the weight
      Object.keys(result.answers || {}).forEach(id => {
        const q = activeQuestions.find(x => x.id === id);
        if (q && result.answers[id] === q.answer && mc[id]) mc[id] = Math.max(0, mc[id] - 1);
      });
      next.missedCounts = mc;
    }

    if (mode.type === "practice") {
      if (result.pct > (bestExam[mode.id] || 0)) { best = true; next.bestExam = { ...bestExam, [mode.id]: result.pct }; }
    } else if (mode.type === "topic") {
      if (result.pct > (bestTopic[mode.domain] || 0)) { best = true; next.bestTopic = { ...bestTopic, [mode.domain]: result.pct }; }
    } else if (mode.type === "mock") {
      if (result.pct > (bestMock[mode.id] || 0)) { best = true; next.bestMock = { ...bestMock, [mode.id]: result.pct }; }
      // clear saved in-progress state for this mock
      const mp = { ...mockProgress }; delete mp[mode.id]; next.mockProgress = mp;
    }

    persist(next);
    setWasBest(best);
    setView("results");
  };

  const exitQuiz = () => {
    if (mode && mode.type === "mock") {
      // mock progress already saved via onMockProgress; just leave
      setView("home");
    } else {
      if (confirm("Exit this quiz? Progress will be lost.")) setView("home");
    }
  };

  // ─── ROUTING ───
  if (view === "quiz") {
    return <Quiz title={activeTitle} questions={activeQuestions} instantFeedback={mode.type === "mock" ? false : instant}
      timed={activeTimed} initialState={resumeState} onProgress={onMockProgress}
      onFinish={onFinish} onExit={exitQuiz} />;
  }
  if (view === "results") {
    return <Results result={lastResult} title={activeTitle} questions={activeQuestions} isBest={wasBest}
      showTime={mode.type === "mock"}
      onRetry={() => { if (mode.type === "mock") startMock(mode.id); else if (mode.type === "practice") startPractice(mode.id); else if (mode.type === "topic") startTopic(mode.domain); else startAdaptive(); }}
      onReview={() => setView("review")} onHome={() => setView("home")} />;
  }
  if (view === "review") {
    return <Review questions={activeQuestions} answers={lastResult.answers} onBack={() => setView("results")} />;
  }

  // ─── HOME ───
  return (
    <div className="safe-top safe-bottom" style={{ minHeight: "100vh", paddingBottom: 32 }}>
      {/* Sync badge */}
      <div style={{ position: "fixed", top: "calc(env(safe-area-inset-top) + 10px)", right: 14, zIndex: 50,
        fontSize: 11, fontWeight: 700, padding: "5px 11px", borderRadius: 20,
        background: syncing ? T.violetSoft : cloudOk ? T.greenSoft : T.amberSoft, color: syncing ? T.violet2 : cloudOk ? T.green : T.amber,
        border: `1px solid ${syncing ? T.violet : cloudOk ? T.green : T.amber}44`, transition: "all 0.3s", display: "flex", alignItems: "center", gap: 5 }}>
        {syncing ? (<><span style={{ display: "inline-block", width: 9, height: 9, border: `2px solid ${T.violet2}`,
          borderTopColor: "transparent", borderRadius: "50%", animation: "spin 0.7s linear infinite" }} />Saving</>) : cloudOk ? (<>☁️ Synced</>) : (<>⚠️ Offline</>)}
      </div>

      {/* Header */}
      <div style={{ textAlign: "center", padding: "32px 20px 16px" }}>
        <div className="fadeUp"><Compass size={64} spin /></div>
        <div className="fadeUp" style={{ fontSize: 25, fontWeight: 900, marginTop: 12, letterSpacing: -0.5 }}>VTS Exam Prep</div>
        <div className="fadeUp" style={{ fontSize: 13, color: T.muted, marginTop: 3 }}>Anesthesia &amp; Analgesia · Board Practice</div>
      </div>

      {/* Two readiness rings side by side */}
      <div className="fadeUp" style={{ display: "flex", gap: 12, margin: "0 18px 22px" }}>
        <div style={{ flex: 1, background: `linear-gradient(135deg,${T.card},${T.violetSoft})`, border: `1px solid ${T.violet}33`,
          borderRadius: 18, padding: "18px 12px", textAlign: "center" }}>
          <div style={{ fontSize: 10.5, fontWeight: 700, color: T.muted, letterSpacing: 0.5, textTransform: "uppercase", marginBottom: 10 }}>Practice</div>
          <Ring pct={practiceReadiness} size={104} sublabel={`${practiceExamsTaken}/${NUM_PRACTICE} done`} />
        </div>
        <div style={{ flex: 1, background: `linear-gradient(135deg,${T.card},${T.greenSoft})`, border: `1px solid ${T.green}33`,
          borderRadius: 18, padding: "18px 12px", textAlign: "center" }}>
          <div style={{ fontSize: 10.5, fontWeight: 700, color: T.muted, letterSpacing: 0.5, textTransform: "uppercase", marginBottom: 10 }}>Mock (Real Gauge)</div>
          {mocksTaken > 0
            ? <Ring pct={mockReadiness} size={104} sublabel={`${mocksTaken}/${NUM_MOCKS} taken`} />
            : <div style={{ height: 104, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center" }}>
                <div style={{ fontSize: 26 }}>🔒</div>
                <div style={{ fontSize: 10.5, color: T.muted, marginTop: 6, lineHeight: 1.4 }}>Finish all 6<br />practice exams</div>
              </div>}
        </div>
      </div>

      {/* Gap insight */}
      {mocksTaken > 0 && (
        <div style={{ margin: "-10px 18px 20px", fontSize: 11.5, color: T.muted, textAlign: "center", lineHeight: 1.5 }}>
          Practice {practiceReadiness}% vs. cold mock {mockReadiness}% — the smaller the gap, the more ready she truly is.
        </div>
      )}

      {/* Feedback toggle */}
      <div style={{ margin: "0 18px 6px", fontSize: 12, fontWeight: 700, color: T.muted }}>Practice feedback</div>
      <div style={{ margin: "0 18px 22px", display: "flex", background: T.card, borderRadius: 14, padding: 5, border: `1px solid ${T.border}` }}>
        {[["After each question", true], ["At the end", false]].map(([label, val]) => (
          <button key={label} onClick={() => setInstant(val)}
            style={{ flex: 1, padding: "11px", borderRadius: 10, fontWeight: 700, fontSize: 13,
              background: instant === val ? `linear-gradient(135deg,${T.violet},${T.violet2})` : "transparent",
              color: instant === val ? "#fff" : T.muted, transition: "all 0.15s" }}>{label}</button>
        ))}
      </div>

      {/* Practice Exams */}
      <div style={{ margin: "0 18px 10px", fontSize: 14, fontWeight: 800 }}>📝 Practice Exams</div>
      <div style={{ margin: "0 18px 14px", fontSize: 11.5, color: T.muted }}>Fresh questions &amp; shuffled answers every attempt · {EXAM_SIZE} Q each</div>
      <div style={{ margin: "0 18px 26px", display: "flex", flexDirection: "column", gap: 10 }}>
        {Array.from({ length: NUM_PRACTICE }, (_, i) => i + 1).map(n => {
          const best = bestExam[n] || 0;
          const c = best >= PASS_THRESHOLD ? T.green : best >= 60 ? T.amber : best > 0 ? T.red : T.muted;
          return (
            <button key={n} onClick={() => startPractice(n)}
              style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "16px 18px",
                borderRadius: 16, background: T.card, border: `1px solid ${T.border}`, width: "100%", textAlign: "left" }}>
              <div>
                <div style={{ fontSize: 15, fontWeight: 800 }}>Practice Exam {n}</div>
                <div style={{ fontSize: 12, color: T.muted, marginTop: 2 }}>{EXAM_SIZE} questions · all topics</div>
              </div>
              <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                {best > 0 ? <div style={{ fontSize: 18, fontWeight: 900, color: c }}>{best}%</div>
                  : <div style={{ fontSize: 12, color: T.muted, fontWeight: 600 }}>Not taken</div>}
                <span style={{ fontSize: 20, color: T.violet2 }}>›</span>
              </div>
            </button>
          );
        })}
      </div>

      {/* Adaptive Mode (locked until all 6 practice done) */}
      <div style={{ margin: "0 18px 10px", fontSize: 14, fontWeight: 800 }}>🎯 Adaptive Review</div>
      <div style={{ margin: "0 18px 26px" }}>
        <button onClick={() => allPracticeDone ? startAdaptive() : null} disabled={!allPracticeDone}
          style={{ width: "100%", display: "flex", alignItems: "center", justifyContent: "space-between", padding: "16px 18px",
            borderRadius: 16, background: allPracticeDone ? `linear-gradient(135deg,${T.card},${T.violetSoft})` : T.card,
            border: `1px solid ${allPracticeDone ? T.violet + "55" : T.border}`, textAlign: "left", opacity: allPracticeDone ? 1 : 0.7 }}>
          <div>
            <div style={{ fontSize: 15, fontWeight: 800, display: "flex", alignItems: "center", gap: 8 }}>
              {allPracticeDone ? "🎯" : "🔒"} Focus on My Misses
            </div>
            <div style={{ fontSize: 12, color: T.muted, marginTop: 2 }}>
              {allPracticeDone ? "Targets the questions you get wrong most" : `Unlocks after all ${NUM_PRACTICE} practice exams`}
            </div>
          </div>
          {allPracticeDone && <span style={{ fontSize: 20, color: T.violet2 }}>›</span>}
        </button>
      </div>

      {/* Mock Exams (locked until all 6 practice done) */}
      <div style={{ margin: "0 18px 10px", fontSize: 14, fontWeight: 800 }}>🎓 Mock Exams</div>
      <div style={{ margin: "0 18px 14px", fontSize: 11.5, color: T.muted }}>
        Timed · fresh held-out questions · the honest test-readiness gauge
      </div>
      <div style={{ margin: "0 18px 26px", display: "flex", flexDirection: "column", gap: 10 }}>
        {Array.from({ length: NUM_MOCKS }, (_, i) => i + 1).map(n => {
          const best = bestMock[n] || 0;
          const inProgress = mockProgress[n];
          const c = best >= PASS_THRESHOLD ? T.green : best >= 60 ? T.amber : best > 0 ? T.red : T.muted;
          const locked = !allPracticeDone;
          return (
            <button key={n} onClick={() => locked ? null : startMock(n)} disabled={locked}
              style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "16px 18px",
                borderRadius: 16, background: locked ? T.card : `linear-gradient(135deg,${T.card},${T.greenSoft})`,
                border: `1px solid ${locked ? T.border : T.green + "44"}`, width: "100%", textAlign: "left", opacity: locked ? 0.7 : 1 }}>
              <div>
                <div style={{ fontSize: 15, fontWeight: 800, display: "flex", alignItems: "center", gap: 8 }}>
                  {locked ? "🔒" : "🎓"} Mock Exam {n}
                </div>
                <div style={{ fontSize: 12, color: T.muted, marginTop: 2 }}>
                  {locked ? `Unlocks after all ${NUM_PRACTICE} practice exams`
                    : inProgress ? `▶ In progress — tap to resume` : `${MOCK_SIZE} questions · ${MOCK_SECONDS / 60} min · timed`}
                </div>
              </div>
              <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                {!locked && best > 0 && <div style={{ fontSize: 18, fontWeight: 900, color: c }}>{best}%</div>}
                {!locked && <span style={{ fontSize: 20, color: T.green }}>›</span>}
              </div>
            </button>
          );
        })}
      </div>

      {/* Topic Practice */}
      <div style={{ margin: "0 18px 10px", fontSize: 14, fontWeight: 800 }}>📚 Practice by Topic</div>
      <div style={{ margin: "0 18px", display: "flex", flexWrap: "wrap", gap: 9 }}>
        {DOMAINS.map(dom => {
          const best = bestTopic[dom] || 0;
          const c = best >= 80 ? T.green : best >= 50 ? T.amber : best > 0 ? T.red : T.muted;
          return (
            <button key={dom} onClick={() => startTopic(dom)}
              style={{ padding: "12px 15px", borderRadius: 13, background: T.card,
                border: `1px solid ${best > 0 ? c + "55" : T.border}`, display: "flex", alignItems: "center", gap: 8 }}>
              <span style={{ fontSize: 13, fontWeight: 700, color: T.sub }}>{dom}</span>
              {best > 0 && <span style={{ fontSize: 12, fontWeight: 800, color: c }}>{best}%</span>}
            </button>
          );
        })}
      </div>

      {/* Footer */}
      <div style={{ textAlign: "center", marginTop: 34, padding: "0 24px" }}>
        <div style={{ fontSize: 11, color: T.muted, lineHeight: 1.6 }}>
          {PRACTICE_POOL.length + MOCK_POOL.length} board-level questions · 6 distinct exams · {MOCK_POOL.length} reserved for mocks.<br />
          {syncing ? "☁️ Saving to cloud…" : cloudOk ? "☁️ Scores sync automatically across your devices." : "⚠️ Cloud unreachable — progress is saved on this device and will sync when you're back online."}
        </div>
      </div>
    </div>
  );
}

ReactDOM.createRoot(document.getElementById("root")).render(<App />);
